const a = [1, 2, 3];
const b = [4, 5, 6];

// Copy an array:
const copy = [...a]; // [1, 2, 3] — new array, independent of a

// Combine arrays:
const combined = [...a, ...b]; // [1, 2, 3, 4, 5, 6]

// Insert elements:
const withExtra = [0, ...a, 4]; // [0, 1, 2, 3, 4]

// Pass array elements as function arguments:
const nums = [5, 3, 8, 1];
const max = Math.max(...nums); // equivalent to Math.max(5, 3, 8, 1)
console.log(max); // 8

const base = { a: 1, b: 2 };
const extra = { c: 3, d: 4 };

// Copy an object:
const copy = { ...base }; // { a: 1, b: 2 } — new object reference

// Merge objects:
const merged = { ...base, ...extra }; // { a: 1, b: 2, c: 3, d: 4 }

// Override specific properties:
const updated = { ...base, b: 99 }; // { a: 1, b: 99 }
// Note: later properties override earlier ones with the same key

const defaults = { theme: 'light', lang: 'en', size: 'medium' };
const overrides = { lang: 'fr', size: 'large' };

// Overrides come AFTER defaults — later keys win:
const config = { ...defaults, ...overrides };
console.log(config); // { theme: 'light', lang: 'fr', size: 'large' }

// If overrides came first, defaults would win:
const wrong = { ...overrides, ...defaults };
console.log(wrong); // { lang: 'en', size: 'medium', theme: 'light' }  ← overrides lost!

const [first, second, ...rest] = [1, 2, 3, 4, 5];
console.log(first);  // 1
console.log(second); // 2
console.log(rest);   // [3, 4, 5]

// Useful for head/tail patterns:
const [head, ...tail] = ['a', 'b', 'c', 'd'];
console.log(head); // 'a'
console.log(tail); // ['b', 'c', 'd']

const { name, age, ...rest } = { name: 'Alice', age: 28, role: 'admin', active: true };
console.log(name); // 'Alice'
console.log(age);  // 28
console.log(rest); // { role: 'admin', active: true }

// Collect all arguments into an array
function sum(...numbers) {
  return numbers.reduce((total, n) => total + n, 0);
}

sum(1, 2, 3);       // 6
sum(10, 20, 30, 40); // 100

// Mix regular params with rest:
function log(level, ...messages) {
  messages.forEach(msg => console.log(`[${level}] ${msg}`));
}

log('INFO', 'Server started', 'Port 3000');
// [INFO] Server started
// [INFO] Port 3000

const [user, setUser] = useState({ name: 'Alice', age: 28, bio: '' });

// Update one property — spread copies the rest:
setUser(prev => ({ ...prev, age: 29 }));
// { name: 'Alice', age: 29, bio: '' }

const [items, setItems] = useState(['apple', 'banana']);

// Add at end:
setItems(prev => [...prev, 'cherry']);
// ['apple', 'banana', 'cherry']

// Add at start:
setItems(prev => ['cherry', ...prev]);
// ['cherry', 'apple', 'banana']

// Remove by index:
setItems(prev => [
  ...prev.slice(0, index),
  ...prev.slice(index + 1),
]);

// Remove by value (using filter):
setItems(prev => prev.filter(item => item !== 'banana'));

const [tasks, setTasks] = useState([
  { id: 1, title: 'Write tests', done: false },
  { id: 2, title: 'Deploy', done: false },
]);

function toggleTask(id) {
  setTasks(prev =>
    prev.map(task =>
      task.id === id
        ? { ...task, done: !task.done } // spread to copy, then override 'done'
        : task
    )
  );
}

// Extract known props, forward the rest to the <input>
function TextInput({ label, error, ...rest }) {
  // label and error are consumed by this component
  // rest contains: value, onChange, placeholder, className, id, type, etc.
  return (
    <div>
      {label && <label>{label}</label>}
      <input {...rest} className={`input ${error ? 'input-error' : ''}`} />
      {error && <p className="error-msg">{error}</p>}
    </div>
  );
}

// Usage — all these extras flow through ...rest to the input:
<TextInput
  label="Email"
  error={errors.email}
  type="email"
  name="email"
  value={form.email}
  onChange={handleChange}
  placeholder="you@example.com"
  autoComplete="email"
/>

// An object of props can be spread directly onto a JSX element:
const buttonProps = {
  type: 'submit',
  className: 'btn-primary',
  disabled: isLoading,
  onClick: handleSubmit,
};

// Instead of:
<button type={buttonProps.type} className={buttonProps.className} ...>
  Submit
</button>

// You can write:
<button {...buttonProps}>Submit</button>

const state = {
  user: { name: 'Alice', address: { city: 'NYC' } },
  count: 0,
};

const newState = { ...state, count: 1 };

// Top-level count is independent:
console.log(newState.count); // 1
console.log(state.count);    // 0

// But nested 'user' is still shared:
console.log(newState.user === state.user); // true — same reference!
newState.user.name = 'Bob'; // ❌ This mutates the original state too!

// ✅ To safely update nested objects, spread at each level:
const newState2 = {
  ...state,
  user: { ...state.user, name: 'Bob' },
};
